import numpy as np

def algo(initial_population, individual_upper, individual_lower, objective_function):
    population = initial_population.copy()
    num_individuals, num_variables = population.shape
    evaluations = 0
    best_solution = None
    best_objective = float('inf')
    memory = []
    memory_size = 10

    def adaptive_mutation_factor(evaluations):
        return 0.5 * (1 - (evaluations / 30000))

    def adaptive_crossover_prob(evaluations):
        return np.clip(0.5 + (0.4 * (evaluations / 30000)), 0.5, 0.9)

    while evaluations < 30000:
        for i in range(num_individuals):
            if evaluations >= 30000:
                break
            indices = list(range(num_individuals))
            indices.remove(i)
            a, b, c = np.random.choice(indices, 3, replace=False)
            mutation_factor = adaptive_mutation_factor(evaluations)
            crossover_prob = adaptive_crossover_prob(evaluations)
            mutant = population[a] + mutation_factor * (population[b] - population[c])
            trial = np.copy(population[i])

            for j in range(num_variables):
                if np.random.rand() < crossover_prob:
                    trial[j] = mutant[j]

            f_trial = objective_function(trial)
            evaluations += 1

            if f_trial < best_objective:
                best_objective = f_trial
                best_solution = trial
                if len(memory) < memory_size:
                    memory.append(np.copy(best_solution))
                else:
                    memory[np.random.randint(0, memory_size)] = np.copy(best_solution)

            if f_trial < objective_function(population[i]):
                population[i] = trial

        promising_candidates = [ind for ind in population if objective_function(ind) < best_objective * 1.05]

        for candidate in promising_candidates:
            local_trial = np.copy(candidate)
            perturbation = np.random.normal(0, 0.1, size=num_variables)
            local_trial = np.clip(local_trial + perturbation, individual_lower, individual_upper)
            f_local = objective_function(local_trial)
            evaluations += 1

            if f_local < best_objective:
                best_objective = f_local
                best_solution = local_trial

    return best_solution
